// n8n Code node: Parse Gemini pages output

const raw = $input.first().json?.candidates?.[0]?.content?.parts?.[0]?.text ?? '';

let text = String(raw).trim();

// Remove code fences
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

// Extract JSON object
const match = text.match(/\{[\s\S]*\}/);
if (!match) {
  return [
    {
      json: {
        error: 'No JSON object found',
        raw_text: text
      }
    }
  ];
}

let obj;

try {
  obj = JSON.parse(match[0]);
} catch (e) {
  const fixedStr = match[0].replace(/,\s*([}\]])/g, '$1');
  obj = JSON.parse(fixedStr);
}

const pages = Array.isArray(obj.pages) ? obj.pages : [];

return pages.map((page) => ({
  json: {
    url: page.url || null,
    verdict: page.verdict || null,
    issues: Array.isArray(page.issues) ? page.issues : [],
    quick_wins: Array.isArray(page.quick_wins) ? page.quick_wins : [],
    copy_notes: Array.isArray(page.copy_notes) ? page.copy_notes : [],
    ux_notes: Array.isArray(page.ux_notes) ? page.ux_notes : []
  }
}));

