const out = [];

for (let index = 0; index < items.length; index++) {
  const item = items[index];

  const raw =
    item.json?.candidates?.[0]?.content?.parts?.find(p => p.text)?.text ??
    item.json?.candidates?.[0]?.content?.parts?.[0]?.text ??
    item.json?.text ??
    '';

  let text = String(raw).trim();

  // Strip code fences
  text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

  // Extract JSON object
  const match = text.match(/\{[\s\S]*\}/);
  if (!match) {
    out.push({
      json: {
        error: 'No JSON object found',
        raw_text: text
      },
      pairedItem: index
    });
    continue;
  }

  let obj;
  try {
    obj = JSON.parse(match[0].trim());
  } catch (e) {
    try {
      const fixedStr = match[0].trim().replace(/,\s*([}\]])/g, '$1');
      obj = JSON.parse(fixedStr);
    } catch (e2) {
      out.push({
        json: {
          error: 'JSON parse failed',
          raw_text: text,
          parse_error: String(e2.message || e2)
        },
        pairedItem: index
      });
      continue;
    }
  }

  const pages = Array.isArray(obj.pages) ? obj.pages : [];

  for (const p of pages) {
    out.push({
      json: {
        page: p.url ?? null,
        website_problem: p.verdict ?? null,
        recognizable_reason: Array.isArray(p.issues) ? p.issues.join(' | ') : null,
        consequence_mechanics: Array.isArray(p.ux_notes) ? p.ux_notes.join(' | ') : null,
        preview_asset_exists: null,
        review_time: null,
        micro_yes: Array.isArray(p.quick_wins) ? p.quick_wins.join(' | ') : null,
        subject_label: null,
        sources: item.json?.groundingMetadata?.webSearchQueries ?? []
      },
      pairedItem: index
    });
  }
}

return out;

